with open(TARGET, 'r', encoding='utf-8') as f:
    src = f.read()

marker_pos = src.find(MARKER)
assert marker_pos != -1, f"Marker not found: {MARKER!r}"

import pprint
update_block = "\n\nUNIT_DATA.update(" + pprint.pformat(UNITS, indent=4, width=120) + ")\n"

new_src = src[:marker_pos] + update_block + src[marker_pos:]

with open(TARGET, 'w', encoding='utf-8') as f:
    f.write(new_src)

print(f"Injected {len(UNITS)} units into {TARGET}")
print(f"Unit IDs: {sorted(UNITS.keys())}")
